class Solution:
    def countPaths(self, n: int, roads: list[list[int]]) -> int:
        import heapq
        """
        Time complexity: O((E+V)logV)
        Auxiliary space complexity: O(V + E)
        Tags:
            DS: heap, list
            A: greedy, Dijkstra
            Model: graph
        """
        MOD = 10**9 + 7
        adjs = [[] for _ in range(n)]
        min_time = [float("inf")] * n
        path_counter = [0] * n
        path_counter[0] = 1

        for u, v, t in roads:
            adjs[u].append((v, t))
            adjs[v].append((u, t))

        # heap([(time, node), ...])
        path_heap = [(0, 0)]

        while path_heap:
            t, node = heapq.heappop(path_heap)

            for adj_node, adj_t in adjs[node]:
                if t + adj_t < min_time[adj_node]:
                    min_time[adj_node] = t + adj_t
                    path_counter[adj_node] = path_counter[node]
                    heapq.heappush(path_heap, (min_time[adj_node], adj_node))

                elif t + adj_t == min_time[adj_node]:
                    path_counter[adj_node] = (
                        path_counter[adj_node] + path_counter[node]) % MOD

        return path_counter[n - 1]


