class Solution:
    def countPaths(self, n: int, roads: list[list[int]]) -> int:
        import heapq
        """
        Time complexity: O(E2logV)
        Auxiliary space complexity: O(V + E)
        Tags:
            DS: heap, hash set, list
            A: greedy, Dijkstra
            Model: graph
        """
        MOD = 10**9 + 7
        adjs = [[] for _ in range(n)]
        counter = 0
        min_time = float("inf")

        for u, v, t in roads:
            adjs[u].append((v, t))
            adjs[v].append((u, t))

        # heap([(time, source, destination, path), ...])
        path_heap = [(t, 0, v, set([0])) for v, t in adjs[0]]
        heapq.heapify(path_heap)

        while path_heap:
            t, src, dst, path = heapq.heappop(path_heap)

            if dst == n - 1:
                if (min_time in (float("inf"), t)):
                    min_time = t
                    counter = (counter + 1) % MOD
                    continue
            elif t > min_time:
                break

            for adj_dst, adj_t in adjs[dst]:
                if (adj_dst in path or t + adj_t > min_time):
                    continue

                adj_path = path.copy()
                adj_path.add(adj_dst)
                heapq.heappush(path_heap, (t + adj_t, dst, adj_dst, adj_path))

        return counter


